using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Text.Json;

namespace SiteInspector.Services;

/// <summary>
/// Provides offline-first persistence using IndexedDB via JS interop.
/// All data is stored locally and synced when connectivity returns.
/// </summary>
public class LocalStorageService
{
    private readonly IJSRuntime _js;
    private const string SitesKey = "sites";
    private const string InspectionsKey = "inspections";

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task<List<ConstructionSite>> GetSitesAsync()
    {
        return await GetAsync<List<ConstructionSite>>(SitesKey) ?? new();
    }

    public async Task SaveSiteAsync(ConstructionSite site)
    {
        var sites = await GetSitesAsync();
        var existing = sites.FindIndex(s => s.Id == site.Id);
        if (existing >= 0)
            sites[existing] = site;
        else
            sites.Add(site);
        await SetAsync(SitesKey, sites);
    }

    public async Task DeleteSiteAsync(string siteId)
    {
        var sites = await GetSitesAsync();
        sites.RemoveAll(s => s.Id == siteId);
        await SetAsync(SitesKey, sites);
    }

    public async Task<List<Inspection>> GetInspectionsAsync()
    {
        return await GetAsync<List<Inspection>>(InspectionsKey) ?? new();
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var all = await GetInspectionsAsync();
        return all.Where(i => i.SiteId == siteId).OrderByDescending(i => i.InspectionDate).ToList();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var all = await GetInspectionsAsync();
        return all.FirstOrDefault(i => i.Id == id);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var inspections = await GetInspectionsAsync();
        var existing = inspections.FindIndex(i => i.Id == inspection.Id);
        if (existing >= 0)
            inspections[existing] = inspection;
        else
            inspections.Add(inspection);
        await SetAsync(InspectionsKey, inspections);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        var inspections = await GetInspectionsAsync();
        inspections.RemoveAll(i => i.Id == id);
        await SetAsync(InspectionsKey, inspections);
    }

    public async Task<List<Inspection>> GetPendingSyncInspectionsAsync()
    {
        var all = await GetInspectionsAsync();
        return all.Where(i => i.SyncStatus == SyncStatus.Pending).ToList();
    }

    private async Task<T?> GetAsync<T>(string key)
    {
        var json = await _js.InvokeAsync<string?>("localStorage.getItem", key);
        if (string.IsNullOrEmpty(json)) return default;
        return JsonSerializer.Deserialize<T>(json);
    }

    private async Task SetAsync<T>(string key, T value)
    {
        var json = JsonSerializer.Serialize(value);
        await _js.InvokeVoidAsync("localStorage.setItem", key, json);
    }
}

using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Net.Http.Json;

namespace SiteInspector.Services;

/// <summary>
/// Manages background sync of inspection data when connectivity is available.
/// Monitors online status and triggers sync automatically.
/// </summary>
public class SyncService : IDisposable
{
    private readonly LocalStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private Timer? _syncTimer;
    private bool _isOnline;

    public event Action<bool>? OnConnectivityChanged;
    public event Action<string>? OnSyncStatusChanged;
    public bool IsOnline => _isOnline;
    public int PendingCount { get; private set; }

    public SyncService(LocalStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _isOnline = await _js.InvokeAsync<bool>("navigator.onLine.valueOf");
        _syncTimer = new Timer(async _ => await CheckAndSync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    public async Task CheckAndSync()
    {
        try
        {
            _isOnline = await _js.InvokeAsync<bool>("siteInspector.isOnline");
            OnConnectivityChanged?.Invoke(_isOnline);

            var pending = await _storage.GetPendingSyncInspectionsAsync();
            PendingCount = pending.Count;

            if (_isOnline && pending.Any())
            {
                OnSyncStatusChanged?.Invoke($"Syncing {pending.Count} inspection(s)...");

                foreach (var inspection in pending)
                {
                    try
                    {
                        // Attempt to sync to server
                        var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                        if (response.IsSuccessStatusCode)
                        {
                            inspection.SyncStatus = SyncStatus.Synced;
                            inspection.LastSyncedAt = DateTime.UtcNow;
                            await _storage.SaveInspectionAsync(inspection);
                        }
                        else
                        {
                            inspection.SyncStatus = SyncStatus.Failed;
                            await _storage.SaveInspectionAsync(inspection);
                        }
                    }
                    catch
                    {
                        // Server unavailable — leave as pending for next attempt
                        inspection.SyncStatus = SyncStatus.Pending;
                    }
                }

                PendingCount = (await _storage.GetPendingSyncInspectionsAsync()).Count;
                OnSyncStatusChanged?.Invoke(PendingCount == 0 ? "All synced" : $"{PendingCount} pending");
            }
        }
        catch
        {
            // Offline or error — will retry next cycle
            _isOnline = false;
            OnConnectivityChanged?.Invoke(false);
        }
    }

    public void Dispose()
    {
        _syncTimer?.Dispose();
    }
}

