@page "/inspection/{Id}"
@using SiteInspector.Models
@using SiteInspector.Services
@inject LocalStorageService Storage
@inject NavigationManager Nav

<div class="page-header">
    <button class="btn btn-ghost btn-back" @onclick="GoBack">← Back</button>
    <h1>@(_isNew ? "New Inspection" : "Inspection")</h1>
</div>

@if (_inspection == null)
{
    <p class="loading">Loading...</p>
}
else
{
    <div class="inspection-form">
        <!-- Site & Inspector Info -->
        <section class="section">
            <div class="form-group">
                <label>Site</label>
                @if (_sites.Any())
                {
                    <select @bind="_inspection.SiteId" class="input" @bind:after="OnSiteSelected">
                        <option value="">— Select a site —</option>
                        @foreach (var site in _sites)
                        {
                            <option value="@site.Id">@site.Name</option>
                        }
                    </select>
                }
                <input type="text" @bind="_inspection.SiteName" placeholder="Or type site name" class="input" />
            </div>
            <div class="form-group">
                <label>Inspector</label>
                <input type="text" @bind="_inspection.InspectorName" placeholder="Your name" class="input" />
            </div>
        </section>

        <!-- Checklist -->
        <section class="section">
            <h2>Safety Checklist</h2>
            <div class="checklist">
                @{
                    string? currentCategory = null;
                }
                @foreach (var item in _inspection.Checklist)
                {
                    @if (item.Category != currentCategory)
                    {
                        currentCategory = item.Category;
                        <div class="checklist-category">@currentCategory</div>
                    }
                    <div class="checklist-item @GetItemClass(item)">
                        <div class="checklist-item-header">
                            <span class="checklist-description">@item.Description</span>
                        </div>
                        <div class="checklist-actions">
                            <button class="btn-check @(item.Result == CheckResult.Pass ? "active-pass" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                            <button class="btn-check @(item.Result == CheckResult.Fail ? "active-fail" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                            <button class="btn-check btn-na @(item.Result == CheckResult.NotApplicable ? "active-na" : "")"
                                    @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                            <button class="btn-check btn-note" @onclick="() => ToggleNotes(item)">📝</button>
                        </div>
                        @if (_expandedNotes.Contains(item.Id))
                        {
                            <div class="checklist-notes">
                                <textarea @bind="item.Notes" placeholder="Add notes..." class="input textarea"
                                          @bind:after="() => AutoSave()"></textarea>
                            </div>
                        }
                    </div>
                }
            </div>
        </section>

        <!-- Photos -->
        <section class="section">
            <h2>Photos</h2>
            <div class="photo-section">
                <label class="btn btn-secondary photo-btn">
                    📷 Add Photo
                    <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" style="display:none" />
                </label>

                @if (_inspection.Photos.Any())
                {
                    <div class="photo-grid">
                        @foreach (var photo in _inspection.Photos)
                        {
                            <div class="photo-card">
                                <img src="@photo.DataUrl" alt="@photo.Caption" class="photo-thumb" />
                                <input type="text" @bind="photo.Caption" placeholder="Caption..."
