@code {
    [Parameter] public string? Id { get; set; }

    private Inspection? _inspection;
    private List<ConstructionSite> _sites = new();
    private HashSet<string> _expandedNotes = new();
    private bool _isNew;
    private string _statusMessage = "";
    private Timer? _autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _sites = await Storage.GetSitesAsync();

        if (Id == "new" || string.IsNullOrEmpty(Id))
        {
            _isNew = true;
            _inspection = new Inspection
            {
                Checklist = ChecklistTemplates.GetStandardChecklist()
            };
        }
        else
        {
            _inspection = await Storage.GetInspectionAsync(Id);
            if (_inspection == null)
            {
                Nav.NavigateTo("/");
                return;
            }
        }

        StateHasChanged();
    }

    private void SetResult(ChecklistItem item, CheckResult result)
    {
        // Toggle off if tapping same result
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
        _ = AutoSave();
    }

    private void ToggleNotes(ChecklistItem item)
    {
        if (!_expandedNotes.Add(item.Id))
            _expandedNotes.Remove(item.Id);
    }

    private void OnSiteSelected()
    {
        if (_inspection == null) return;
        var site = _sites.FirstOrDefault(s => s.Id == _inspection.SiteId);
        if (site != null)
            _inspection.SiteName = site.Name;
    }

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        if (_inspection == null) return;

        foreach (var file in e.GetMultipleFiles(5))
        {
            if (file.Size > 10 * 1024 * 1024) continue; // Skip files over 10MB

            var buffer = new byte[file.Size];
            await file.OpenReadStream(10 * 1024 * 1024).ReadAsync(buffer);
            var dataUrl = $"data:{file.ContentType};base64,{Convert.ToBase64String(buffer)}";

            _inspection.Photos.Add(new PhotoAttachment
            {
                FileName = file.Name,
                DataUrl = dataUrl,
                TakenAt = DateTime.UtcNow
            });
        }

        await AutoSave();
    }

    private async Task RemovePhoto(PhotoAttachment photo)
    {
        _inspection?.Photos.Remove(photo);
        await AutoSave();
    }

    private async Task AutoSave()
    {
        if (_inspection == null) return;
        _inspection.SyncStatus = SyncStatus.Pending;
        await Storage.SaveInspectionAsync(_inspection);
    }

    private async Task SaveDraft()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.InProgress;
        await AutoSave();
        ShowToast("Draft saved ✓");
        Nav.NavigateTo("/");
    }

    private async Task CompleteInspection()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.Completed;
        await AutoSave();
        ShowToast("Inspection completed ✓");
        Nav.NavigateTo("/");
    }

    private void GoBack()
    {
        Nav.NavigateTo("/");
    }

    private async void ShowToast(string message)
    {
        _statusMessage = message;
        StateHasChanged();
        await Task.Delay(2000);
        _statusMessage = "";
        StateHasChanged();
    }
}
