arguments.new_str:
@page "/"
@using SiteInspector.Models
@using SiteInspector.Services
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Site Inspector</PageTitle>

<div class="page-header">
    <h1>🏗️ Site Inspector</h1>
    <p class="subtitle">Construction Safety Inspections</p>
</div>

<div class="action-bar">
    <button class="btn btn-primary btn-large" @onclick="StartNewInspection">
        ➕ New Inspection
    </button>
</div>

<section class="section">
    <h2>Recent Inspections</h2>
    @if (_inspections == null)
    {
        <p class="loading">Loading...</p>
    }
    else if (!_inspections.Any())
    {
        <div class="empty-state">
            <p>No inspections yet.</p>
            <p>Tap <strong>New Inspection</strong> to get started.</p>
        </div>
    }
    else
    {
        <div class="card-list">
            @foreach (var inspection in _inspections.Take(10))
            {
                <div class="card" @onclick="() => OpenInspection(inspection.Id)">
                    <div class="card-header">
                        <span class="card-title">@inspection.SiteName</span>
                        <span class="badge @GetStatusClass(inspection)">@GetStatusLabel(inspection)</span>
                    </div>
                    <div class="card-body">
                        <span class="card-date">📅 @inspection.InspectionDate.ToString("MMM d, yyyy h:mm tt")</span>
                        <span class="card-progress">
                            ✅ @inspection.Checklist.Count(c => c.Result != CheckResult.NotChecked)/@inspection.Checklist.Count
                        </span>
                    </div>
                    <div class="card-footer">
                        @if (inspection.SyncStatus == SyncStatus.Pending)
                        {
                            <span class="sync-badge pending">⏳ Not synced</span>
                        }
                        else if (inspection.SyncStatus == SyncStatus.Synced)
                        {
                            <span class="sync-badge synced">☁️ Synced</span>
                        }
                    </div>
                </div>
            }
        </div>
    }
</section>

<section class="section">
    <h2>Sites</h2>
    <button class="btn btn-secondary" @onclick="() => _showAddSite = true">+ Add Site</button>

    @if (_showAddSite)
    {
        <div class="inline-form">
            <input type="text" @bind="_newSiteName" placeholder="Site name" class="input" />
            <input type="text" @bind="_newSiteAddress" placeholder="Address" class="input" />
            <div class="form-actions">
                <button class="btn btn-primary" @onclick="AddSite">Save</button>
                <button class="btn btn-ghost" @onclick="() => _showAddSite = false">Cancel</button>
            </div>
        </div>
    }

    @if (_sites?.Any() == true)
    {
        <div class="card-list">
            @foreach (var site in _sites)
            {
                <div class="card card-compact">
                    <span class="card-title">@site.Name</span>
                    <span class="card-subtitle">@site.Address</span>
                </div>
            }
        </div>
    }
</section>

@code {
    private List<Inspection>? _inspections;
    private List<ConstructionSite>? _sites;
    private bool _showAddSite;
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _inspections = await Storage.GetInspectionsAsync();
            _inspections = _inspections.OrderByDescending(i => i.InspectionDate).ToList();
            _sites = await Storage.GetSitesAsync();
            StateHasChanged();
        }
    }

    private void StartNewInspection()
    {
        Nav.NavigateTo("/inspection/new");
    }

    private void OpenInspection(string id)
    {
        Nav.NavigateTo($"/inspection/{id}");
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new ConstructionSite
        {
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim()
        };
        await Storage.SaveSiteAsync(site);
        _sites = await Storage.GetSitesAsync();
        _newSiteName = "";
        _newSiteAddress = "";
        _showAddSite = false;
    }

    private string GetStatusClass(Inspection i) => i.Status switch
    {
        InspectionStatus.Completed => "badge-success",
        _ => "badge-warning"
    };

    private string GetStatusLabel(Inspection i) => i.Status switch
    {
        InspectionStatus.Completed => "Complete",
        _ => "In Progress"
    };
}

