@inherits LayoutComponentBase
@using SiteInspector.Services
@inject SyncService Sync

<div class="app-container">
    <header class="app-header">
        <div class="connectivity-indicator @(_isOnline ? "online" : "offline")">
            @(_isOnline ? "🟢 Online" : "🔴 Offline")
        </div>
        @if (_pendingCount > 0)
        {
            <div class="sync-indicator">⏳ @_pendingCount pending</div>
        }
    </header>

    <main class="app-main">
        @Body
    </main>
</div>

@code {
    private bool _isOnline;
    private int _pendingCount;

    protected override void OnInitialized()
    {
        Sync.OnConnectivityChanged += OnConnectivityChanged;
        Sync.OnSyncStatusChanged += OnSyncStatusChanged;
        _isOnline = Sync.IsOnline;
        _pendingCount = Sync.PendingCount;
    }

    private void OnConnectivityChanged(bool online)
    {
        _isOnline = online;
        InvokeAsync(StateHasChanged);
    }

    private void OnSyncStatusChanged(string status)
    {
        _pendingCount = Sync.PendingCount;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Sync.OnConnectivityChanged -= OnConnectivityChanged;
        Sync.OnSyncStatusChanged -= OnSyncStatusChanged;
    }
}

