/* Site Inspector - Mobile-first construction inspection app */
:root {
    --primary: #1a73e8;
    --primary-dark: #1557b0;
    --success: #34a853;
    --danger: #ea4335;
    --warning: #f9ab00;
    --gray-50: #f8f9fa;
    --gray-100: #f1f3f4;
    --gray-200: #e8eaed;
    --gray-300: #dadce0;
    --gray-500: #80868b;
    --gray-700: #5f6368;
    --gray-900: #202124;
    --radius: 12px;
    --radius-sm: 8px;
    --shadow: 0 1px 3px rgba(0,0,0,0.12), 0 1px 2px rgba(0,0,0,0.08);
    --shadow-md: 0 4px 6px rgba(0,0,0,0.1), 0 2px 4px rgba(0,0,0,0.06);
}

* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 16px;
    line-height: 1.5;
    color: var(--gray-900);
    background: var(--gray-50);
    -webkit-font-smoothing: antialiased;
    overflow-x: hidden;
}

/* App Layout */
.app-container {
    min-height: 100vh;
    max-width: 768px;
    margin: 0 auto;
    padding-bottom: env(safe-area-inset-bottom, 20px);
}

.app-header {
    position: sticky;
    top: 0;
    z-index: 100;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 8px 16px;
    background: white;
    border-bottom: 1px solid var(--gray-200);
    font-size: 0.8rem;
}

.connectivity-indicator {
    padding: 4px 8px;
    border-radius: 12px;
    font-weight: 500;
}
.connectivity-indicator.online { background: #e6f4ea; color: var(--success); }
.connectivity-indicator.offline { background: #fce8e6; color: var(--danger); }

.sync-indicator {
    color: var(--warning);
    font-weight: 500;
}

.app-main {
    padding: 16px;
}

/* Typography */
h1 { font-size: 1.5rem; margin: 0; font-weight: 700; }
h2 { font-size: 1.1rem; margin: 0 0 12px; font-weight: 600; color: var(--gray-700); }

.page-header {
    margin-bottom: 20px;
}
.page-header .subtitle {
    margin: 4px 0 0;
    color: var(--gray-500);
    font-size: 0.9rem;
}

/* Buttons */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    padding: 10px 20px;
    border: none;
    border-radius: var(--radius-sm);
    font-size: 0.95rem;
    font-weight: 500;
    cursor: pointer;
    transition: all 0.15s;
    touch-action: manipulation;
    user-select: none;
}
.btn:active { transform: scale(0.96); }

.btn-primary { background: var(--primary); color: white; }
.btn-primary:hover { background: var(--primary-dark); }

.btn-secondary { background: var(--gray-100); color: var(--gray-900); border: 1px solid var(--gray-300); }
.btn-ghost { background: transparent; color: var(--gray-700); padding: 8px 12px; }

.btn-large { padding: 14px 28px; font-size: 1.05rem; width: 100%; border-radius: var(--radius); }
.btn-sm { padding: 6px 10px; font-size: 0.8rem; }
.btn-back { padding: 8px 0; margin-bottom: 8px; font-size: 1rem; }

.action-bar {
    margin-bottom: 24px;
}

/* Forms */
.input {
    width: 100%;
    padding: 12px 14px;
    border: 1px solid var(--gray-300);
    border-radius: var(--radius-sm);
    font-size: 1rem;
    background: white;
    transition: border-color 0.15s;
